'use client';

import React, { useState, useMemo, useEffect, useRef, useCallback } from 'react';
import { useRouter } from 'next/navigation';
import { motion, AnimatePresence } from 'framer-motion';
import {
  Search as SearchIcon,
  BookOpen,
  Star,
  HelpCircle,
  Layers,
  BookMarked,
  FileText,
  Sparkles,
  TrendingUp,
} from 'lucide-react';
import Fuse from 'fuse.js';
import { themes } from '@/data/themes';
import { contentItems } from '@/data/content';
import { quizQuestions } from '@/data/quiz';
import { flashcardDecks } from '@/data/flashcards';
import { books, bookPassages } from '@/data/books';
import type { SearchResult, SearchResultType } from '@/types';
import PageHeader from '@/components/layout/PageHeader';
import SearchInput from '@/components/ui/SearchInput';
import Card from '@/components/ui/Card';
import Badge from '@/components/ui/Badge';
import EmptyState from '@/components/ui/EmptyState';

// --- Filter types ---
interface FilterChip {
  id: SearchResultType | 'all';
  label: string;
}

const filters: FilterChip[] = [
  { id: 'all', label: 'Tous' },
  { id: 'theme', label: 'Thèmes' },
  { id: 'verse', label: 'Versets' },
  { id: 'hadith', label: 'Hadiths' },
  { id: 'quiz', label: 'Quiz' },
  { id: 'flashcard', label: 'Flashcards' },
  { id: 'book', label: 'Livres' },
  { id: 'passage', label: 'Passages' },
];

const popularSearches = ['Tawhid', 'Prière', 'Patience', 'Coran', 'Hadith', 'Purification', 'Invocations', 'Sira'];

// --- Type display config ---
const typeConfig: Record<SearchResultType, { label: string; variant: 'green' | 'gold' | 'teal' | 'blue' | 'default'; color: string }> = {
  theme: { label: 'Thème', variant: 'green', color: 'var(--color-primary-400, #59b778)' },
  verse: { label: 'Verset', variant: 'green', color: 'var(--color-primary-400, #59b778)' },
  hadith: { label: 'Hadith', variant: 'gold', color: 'var(--color-gold-400, #e0ad3a)' },
  reminder: { label: 'Rappel', variant: 'teal', color: 'var(--color-teal-400, #34c9b4)' },
  quiz: { label: 'Quiz', variant: 'teal', color: 'var(--color-teal-400, #34c9b4)' },
  flashcard: { label: 'Flashcard', variant: 'blue', color: '#a78bfa' },
  book: { label: 'Livre', variant: 'default', color: 'var(--text-secondary, #a8b4c2)' },
  passage: { label: 'Passage', variant: 'gold', color: 'var(--color-gold-300, #f0c95c)' },
};

// --- Framer Motion variants ---
const containerVariants = {
  hidden: { opacity: 0 },
  visible: { opacity: 1, transition: { staggerChildren: 0.05 } },
};

const itemVariants = {
  hidden: { opacity: 0, y: 16 },
  visible: { opacity: 1, y: 0, transition: { duration: 0.35, ease: 'easeOut' } },
};

const fadeVariants = {
  initial: { opacity: 0, y: 8 },
  animate: { opacity: 1, y: 0, transition: { duration: 0.3 } },
  exit: { opacity: 0, y: -8, transition: { duration: 0.2 } },
};

// --- Build unified search index ---
function buildSearchIndex(): SearchResult[] {
  const index: SearchResult[] = [];

  for (const t of themes) {
    index.push({ id: t.id, type: 'theme', title: t.title, preview: t.description, score: 0 });
  }

  for (const item of contentItems) {
    const type: SearchResultType = (item.type === 'verse' || item.type === 'hadith' || item.type === 'reminder')
      ? item.type
      : 'reminder';
    index.push({
      id: item.id,
      type,
      title: item.title || item.type,
      preview: item.content.substring(0, 150),
      themeId: item.themeId,
      score: 0,
    });
  }

  for (const q of quizQuestions) {
    index.push({
      id: q.id,
      type: 'quiz',
      title: q.question,
      preview: q.explanation.substring(0, 150),
      themeId: q.themeId,
      score: 0,
    });
  }

  for (const d of flashcardDecks) {
    index.push({
      id: d.id,
      type: 'flashcard',
      title: d.title,
      preview: d.description,
      themeId: d.themeId,
      score: 0,
    });
  }

  for (const b of books) {
    index.push({
      id: b.id,
      type: 'book',
      title: b.title,
      preview: b.author + ' – ' + (b.description || '').substring(0, 100),
      score: 0,
    });
  }

  for (const p of bookPassages) {
    index.push({
      id: p.id,
      type: 'passage',
      title: p.title,
      preview: p.content.substring(0, 150),
      score: 0,
    });
  }

  return index;
}

// --- Navigation helpers ---
function getResultHref(result: SearchResult): string {
  switch (result.type) {
    case 'theme':
      return `/explore/${result.id}`;
    case 'verse':
    case 'hadith':
    case 'reminder':
      return result.themeId ? `/explore/${result.themeId}` : '/explore';
    case 'quiz':
      return '/quiz';
    case 'flashcard':
      return '/flashcards';
    case 'book':
      return `/books/${result.id}`;
    case 'passage':
      return '/books';
    default:
      return '/explore';
  }
}

// --- Component ---
export default function SearchPage() {
  const router = useRouter();
  const inputRef = useRef<HTMLInputElement>(null);
  const [query, setQuery] = useState('');
  const [debouncedQuery, setDebouncedQuery] = useState('');
  const [activeFilter, setActiveFilter] = useState<SearchResultType | 'all'>('all');

  // Debounce search input
  useEffect(() => {
    const timer = setTimeout(() => setDebouncedQuery(query), 300);
    return () => clearTimeout(timer);
  }, [query]);

  // Auto-focus on mount
  useEffect(() => {
    inputRef.current?.focus();
  }, []);

  // Build fuse index once
  const searchIndex = useMemo(() => buildSearchIndex(), []);
  const fuse = useMemo(
    () =>
      new Fuse(searchIndex, {
        keys: ['title', 'preview'],
        threshold: 0.4,
        includeScore: true,
      }),
    [searchIndex]
  );

  // Search results
  const results = useMemo<SearchResult[]>(() => {
    if (debouncedQuery.length < 2) return [];
    const fuseResults = fuse.search(debouncedQuery);
    return fuseResults.map((r) => ({ ...r.item, score: r.score ?? 0 }));
  }, [debouncedQuery, fuse]);

  // Filtered results
  const filteredResults = useMemo(() => {
    if (activeFilter === 'all') return results;
    return results.filter((r) => r.type === activeFilter);
  }, [results, activeFilter]);

  const isSearching = debouncedQuery.length >= 2;

  const handlePopularSearch = useCallback((term: string) => {
    setQuery(term);
    setDebouncedQuery(term);
  }, []);

  const handleResultClick = useCallback(
    (result: SearchResult) => {
      router.push(getResultHref(result));
    },
    [router]
  );

  return (
    <div className="pb-nav space-y-5 py-4 sm:py-6">
      <PageHeader title="Rechercher" />

      {/* Search input */}
      <SearchInput
        ref={inputRef}
        value={query}
        onChange={setQuery}
        placeholder="Rechercher dans Ilmify..."
        className="text-base"
      />

      {/* Filter chips */}
      {isSearching && (
        <motion.div
          initial={{ opacity: 0, y: -4 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.25 }}
          className="flex gap-2 overflow-x-auto no-scrollbar pb-1"
        >
          {filters.map((f) => {
            const isActive = activeFilter === f.id;
            const count = f.id === 'all'
              ? results.length
              : results.filter((r) => r.type === f.id).length;

            if (f.id !== 'all' && count === 0) return null;

            return (
              <button
                key={f.id}
                onClick={() => setActiveFilter(f.id)}
                className="shrink-0 rounded-xl px-4 py-2 text-sm font-medium transition-all duration-200 cursor-pointer"
                style={{
                  background: isActive ? 'rgba(58, 170, 96, 0.15)' : 'var(--bg-secondary)',
                  color: isActive ? '#59b778' : 'var(--text-muted)',
                  border: isActive
                    ? '1px solid rgba(58, 170, 96, 0.3)'
                    : '1px solid var(--border-subtle)',
                }}
              >
                {f.label}
                {count > 0 && (
                  <span className="ml-1.5 opacity-60">{count}</span>
                )}
              </button>
            );
          })}
        </motion.div>
      )}

      {/* Content area */}
      <AnimatePresence mode="wait">
        {!isSearching ? (
          /* --- Idle state --- */
          <motion.div
            key="idle"
            variants={fadeVariants}
            initial="initial"
            animate="animate"
            exit="exit"
            className="space-y-8"
          >
            {/* Popular searches */}
            <section>
              <div className="flex items-center gap-2 mb-3">
                <TrendingUp size={16} style={{ color: 'var(--color-primary-400, #59b778)' }} />
                <h2
                  className="text-sm font-semibold uppercase tracking-wider"
                  style={{ color: 'var(--text-secondary)' }}
                >
                  Recherches populaires
                </h2>
              </div>
              <div className="flex flex-wrap gap-2">
                {popularSearches.map((term) => (
                  <button
                    key={term}
                    onClick={() => handlePopularSearch(term)}
                    className="rounded-xl px-4 py-2 text-sm font-medium transition-all duration-200 cursor-pointer hover:scale-105"
                    style={{
                      background: 'var(--bg-secondary)',
                      color: 'var(--text-secondary)',
                      border: '1px solid var(--border-subtle)',
                    }}
                  >
                    {term}
                  </button>
                ))}
              </div>
            </section>

            {/* Category quick links */}
            <section>
              <div className="flex items-center gap-2 mb-3">
                <Sparkles size={16} style={{ color: 'var(--color-gold-400, #e0ad3a)' }} />
                <h2
                  className="text-sm font-semibold uppercase tracking-wider"
                  style={{ color: 'var(--text-secondary)' }}
                >
                  Catégories
                </h2>
              </div>
              <div className="grid grid-cols-2 sm:grid-cols-3 lg:grid-cols-4 gap-3">
                {themes.slice(0, 8).map((theme) => (
                  <Card
                    key={theme.id}
                    hoverable
                    glowColor="green"
                    onClick={() => router.push(`/explore/${theme.id}`)}
                  >
                    <div className="p-4 flex items-center gap-3">
                      <div
                        className="flex h-9 w-9 shrink-0 items-center justify-center rounded-lg text-sm font-bold"
                        style={{ background: `${theme.color}20`, color: theme.color }}
                      >
                        {theme.title.charAt(0)}
                      </div>
                      <span
                        className="text-sm font-medium truncate"
                        style={{ color: 'var(--text-primary)' }}
                      >
                        {theme.title}
                      </span>
                    </div>
                  </Card>
                ))}
              </div>
            </section>
          </motion.div>
        ) : filteredResults.length === 0 ? (
          /* --- No results --- */
          <motion.div
            key="empty"
            variants={fadeVariants}
            initial="initial"
            animate="animate"
            exit="exit"
          >
            <EmptyState
              icon={SearchIcon}
              title="Aucun résultat"
              description={`Aucun résultat pour "${debouncedQuery}". Essayez un autre terme.`}
              actionLabel="Effacer"
              onAction={() => {
                setQuery('');
                setDebouncedQuery('');
                setActiveFilter('all');
              }}
            />
          </motion.div>
        ) : (
          /* --- Results list --- */
          <motion.div
            key={'results-' + activeFilter}
            variants={fadeVariants}
            initial="initial"
            animate="animate"
            exit="exit"
            className="space-y-4"
          >
            {/* Result count */}
            <p className="text-xs font-medium" style={{ color: 'var(--text-muted)' }}>
              {filteredResults.length} résultat{filteredResults.length !== 1 ? 's' : ''}
            </p>

            <motion.div
              variants={containerVariants}
              initial="hidden"
              animate="visible"
              className="space-y-3"
            >
              {filteredResults.map((result) => {
                const config = typeConfig[result.type];

                return (
                  <motion.div key={result.type + '-' + result.id} variants={itemVariants}>
                    <Card hoverable onClick={() => handleResultClick(result)}>
                      <div className="p-4 sm:p-5">
                        <div className="flex items-start gap-3">
                          {/* Type icon */}
                          <div
                            className="flex h-9 w-9 shrink-0 items-center justify-center rounded-lg mt-0.5"
                            style={{ background: `${config.color}15`, color: config.color }}
                          >
                            <ResultTypeIcon type={result.type} />
                          </div>

                          <div className="min-w-0 flex-1">
                            <div className="flex items-center gap-2 mb-1">
                              <Badge variant={config.variant} size="sm">
                                {config.label}
                              </Badge>
                            </div>
                            <h3
                              className="text-sm font-semibold leading-snug line-clamp-2 mb-1"
                              style={{ color: 'var(--text-primary)' }}
                            >
                              {result.title}
                            </h3>
                            <p
                              className="text-xs leading-relaxed line-clamp-2"
                              style={{ color: 'var(--text-muted)' }}
                            >
                              {result.preview}
                            </p>
                          </div>
                        </div>
                      </div>
                    </Card>
                  </motion.div>
                );
              })}
            </motion.div>
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
}

// --- Helper: icon per type ---
function ResultTypeIcon({ type }: { type: SearchResultType }) {
  const size = 18;
  switch (type) {
    case 'theme':
      return <Layers size={size} />;
    case 'verse':
      return <BookOpen size={size} />;
    case 'hadith':
      return <Star size={size} />;
    case 'reminder':
      return <Sparkles size={size} />;
    case 'quiz':
      return <HelpCircle size={size} />;
    case 'flashcard':
      return <FileText size={size} />;
    case 'book':
      return <BookMarked size={size} />;
    case 'passage':
      return <FileText size={size} />;
    default:
      return <SearchIcon size={size} />;
  }
}
